  "auth.roleServiced": {"en":"Serviced Office Operator","fr":"Opérateur de bureaux équipés","de":"Betreiber von Serviced Offices","es":"Operador de oficinas equipadas","it":"Operatore di uffici attrezzati","nl":"Exploitant van serviced offices"},
